from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent sentence (or sentences) that summarize the provided triples."""
    if not triples:
        return ""
    # Helper to create a natural‑language phrase for a single triple
    def phrase(triple: Triple) -> str:
        subj, pred, obj = triple.subject, triple.predicate, triple.object
        # Simple mapping of predicates to readable fragments
        if pred == "location":
            return f"{subj} is located in {obj}"
        if pred == "architecturalStyle":
            return f"{subj} has an architectural style of {obj}"
        if pred == "buildingStartDate":
            return f"Construction of {subj} started in {obj}"
        if pred == "completionDate":
            return f"{subj} was completed in {obj}"
        if pred == "floorCount":
            return f"{subj} has {obj} floors"
        if pred == "floorArea":
            return f"{subj} covers a floor area of {obj} square metres"
        if pred == "height":
            return f"{subj} is {obj} metres tall"
        if pred == "cost":
            return f"{subj} cost {obj}"
        if pred == "owner":
            return f"{subj} is owned by {obj}"
        if pred == "architect":
            return f"{subj} was designed by {obj}"
        if pred == "developer":
            return f"{subj} was developed by {obj}"
        if pred == "tenant":
            return f"{subj} has a tenant {obj}"
        if pred == "isPartOf":
            return f"{subj} is part of {obj}"
        if pred == "country":
            return f"{subj} is in {obj}"
        if pred == "capital":
            return f"{obj} is the capital of {subj}"
        if pred == "leader":
            return f"{obj} leads {subj}"
        if pred == "currency":
            return f"{obj} is the currency of {subj}"
        if pred == "formerName":
            return f"{subj} was formerly known as {obj}"
        if pred == "buildingType":
            return f"{subj} is a {obj}"
        if pred == "currentTenants":
            return f"{subj} currently houses {obj}"
        if pred == "address":
            return f"{subj} is located at {obj}"
        if pred == "inaugurationDate":
            return f"{subj} was inaugurated on {obj}"
        if pred == "birthPlace":
            return f"{subj} was born in {obj}"
        if pred == "deathPlace":
            return f"{subj} died in {obj}"
        if pred == "bedCount":
            return f"{subj} has {obj} beds"
        if pred == "region":
            return f"{subj} is in the region of {obj}"
        if pred == "state":
            return f"{subj} is in the state of {obj}"
        if pred == "website":
            return f"The website of {subj} is {obj}"
        if pred == "yearOfConstruction":
            return f"{subj} was built in {obj}"
        # Fallback: generic wording
        return f"{subj} {pred.replace('_', ' ')} {obj}"
    # Group triples by subject while preserving order
    groups = {}
    order = []
    for t in triples:
        if t.subject not in groups:
            groups[t.subject] = []
            order.append(t.subject)
        groups[t.subject].append(t)
    # Build sentences for each subject group
    sentences = []
    for subj in order:
        group = groups[subj]
        if len(group) == 1:
            sentences.append(phrase(group[0]))
        else:
            # Combine multiple phrases for the same subject
            parts = [phrase(tr) for tr in group]
            # Join with commas and an 'and' before the last part
            combined = ", ".join(parts[:-1]) + f", and {parts[-1]}"
            sentences.append(combined)
    # Join all subject sentences into a final paragraph
    return " ".join(sentences)

# EVOLVE-BLOCK-END

